// criando variáveis
let valor = 10;
console.log(`Valor = ${valor}`);
// atribuição de adição
valor += 10;
console.log(`Novo valor = ${valor}`);
// atribuição de subtração
valor -= 10;
console.log(`Novo valor = ${valor}`);
// atribuição de multiplicação
valor *= 10;
console.log(`Novo valor = ${valor}`);
// atribuição de divisão
valor /= 10;
console.log(`Novo valor = ${valor}`);
// atribuição de exponenciação
valor **= 10;
console.log(`Novo valor = ${valor}`);
// atribuição de resto
valor %= 10;
console.log(`Novo valor = ${valor}`);